Source code in <code>src/simplendarray/transpiler/runtime.py</code> <pre><code>def compile_fn(
    self, types: Iterable[_SpecItem] | None = None, c_attrs: list[str] | None = None, pybind: bool = False
):
    if c_attrs is None:
        c_attrs = []

    class IndexableFunction[R, **P]:  # pragma: no cover
        # Purely for type hinting
        def __init__(self, fn: Callable[P, R]):
            self.fn = fn

        def __call__(self, *args: P.args, **kwargs: P.kwargs):
            return self.fn(*args, **kwargs)

        def __getitem__(self, _idx):
            return self

    def decorator[R, **P](func: Callable[P, R]) -&gt; IndexableFunction[R, P]:
        if types:
            specs = _normalize_specs(types)
            src = dedent(inspect.getsource(func))
            tree = ast.parse(src)
            fn = tree.body[0]
            if not isinstance(fn, ast.FunctionDef):
                raise ValueError("only function definitions can be compiled")
            for spec in specs:
                mangled = _mangled_name(func.__name__, spec)
                fn_copy = copy.deepcopy(fn)
                substituter = _TypeSubstituter(spec, mangled)
                specialized = substituter.visit(fn_copy)
                ast.fix_missing_locations(specialized)
                if "Op" in spec:
                    group = spec["Op"].lstrip("_")
                else:
                    group = func.__name__
                dispatch_key = spec.get("T")
                self._register_ast(mangled, specialized, c_attrs, pybind, group=group, dispatch_key=dispatch_key)
        else:
            group = func.__name__
            self._register(func, c_attrs, pybind, group=group)
        return IndexableFunction(func)

    return decorator
